/* config.h for libarchive - Windows MSVC build */
#ifndef CONFIG_H_INCLUDED
#define CONFIG_H_INCLUDED

/* Define to 1 if you have the <windows.h> header file. */
#define HAVE_WINDOWS_H 1

/* Define to 1 if you have the <io.h> header file. */
#define HAVE_IO_H 1

/* Define to 1 if you have the <fcntl.h> header file. */
#define HAVE_FCNTL_H 1

/* Define to 1 if you have the <sys/stat.h> header file. */
#define HAVE_SYS_STAT_H 1

/* Define to 1 if you have the <sys/types.h> header file. */
#define HAVE_SYS_TYPES_H 1

/* Define to 1 if you have the <string.h> header file. */
#define HAVE_STRING_H 1

/* Define to 1 if you have the <stdlib.h> header file. */
#define HAVE_STDLIB_H 1

/* Define to 1 if you have the <time.h> header file. */
#define HAVE_TIME_H 1

/* Define to 1 if you have the `_mkdir' function. */
#define HAVE__MKDIR 1

/* Define to 1 if you have the `_stat64' function. */
#define HAVE__STAT64 1

/* Define to 1 if you have the `wcscpy' function. */
#define HAVE_WCSCPY 1

/* Define to 1 if you have the `wcslen' function. */
#define HAVE_WCSLEN 1

/* Define to 1 if you have the `_open' function. */
#define HAVE__OPEN 1

/* Define to 1 if you have the `_close' function. */
#define HAVE__CLOSE 1

/* Define to 1 if you have the `_read' function. */
#define HAVE__READ 1

/* Define to 1 if you have the `_write' function. */
#define HAVE__WRITE 1

/* Version number of package */
#define VERSION "3.7.6"

/* Define to 1 if you want RAR read support */
#define HAVE_RAR 1

/* Define to 1 if you want RAR5 read support */
#define HAVE_RAR5 1

/* Define LIBARCHIVE_STATIC for static library */
#define LIBARCHIVE_STATIC 1

/* Windows platform */
#define PLATFORM_CONFIG_H 1

#endif /* CONFIG_H_INCLUDED */
